// Frontend-side frontmatter utilities for display purposes only.
// Authoritative YAML parsing is performed by Rust backend (serde_yaml).
// These functions are for CodeMirror decoration and copy-button text extraction.

/**
 * Frontmatter delimiter used in .md files.
 */
const FRONTMATTER_DELIMITER = '---';

/**
 * Detect frontmatter boundaries in document text.
 * Used by CodeMirror 6 ViewPlugin/StateField for background color decoration.
 *
 * Rules (matching Rust-side detection in module:storage):
 *   1. Document must start with "---" on line 0
 *   2. Closing "---" must appear on a subsequent line (exact match, no trailing content)
 *   3. Returns null if no valid frontmatter block is found
 *
 * This is a DISPLAY-ONLY function. It does not parse YAML.
 * Actual YAML deserialization happens in Rust (serde_yaml).
 */
export function detectFrontmatterRange(
  doc: string
): { startLine: number; endLine: number; startOffset: number; endOffset: number } | null {
  const lines = doc.split('\n');

  if (lines.length === 0 || lines[0].trim() !== FRONTMATTER_DELIMITER) {
    return null;
  }

  for (let i = 1; i < lines.length; i++) {
    if (lines[i].trim() === FRONTMATTER_DELIMITER) {
      // Calculate character offsets
      let startOffset = 0;
      let endOffset = 0;
      for (let j = 0; j <= i; j++) {
        if (j === i) {
          endOffset = startOffset + lines[j].length;
        }
        if (j < i) {
          startOffset += lines[j].length + 1; // +1 for \n
        }
      }
      // Recalculate startOffset to be 0 (beginning of document)
      return {
        startLine: 0,
        endLine: i,
        startOffset: 0,
        endOffset: endOffset,
      };
    }
  }

  return null;
}

/**
 * Extract body text (everything after frontmatter) from full document content.
 * Used by CopyButton.svelte — CONV-3 specifies copy target is full document text.
 *
 * NOTE: Per detail:editor_clipboard §4.3 CONV-3, the copy button copies the FULL
 * document (frontmatter included). This function is provided as a utility if
 * body-only extraction is ever needed, but the copy button should use
 * EditorView.state.doc.toString() directly for the full content.
 */
export function extractBody(doc: string): string {
  const range = detectFrontmatterRange(doc);
  if (range === null) {
    return doc;
  }

  // Skip past the closing --- and any immediately following blank line
  const afterFrontmatter = doc.substring(range.endOffset);
  // Remove leading newlines (typically one blank line after ---)
  return afterFrontmatter.replace(/^\n+/, '');
}

/**
 * Default frontmatter template for new notes.
 * Generated by module:editor when creating a new note via Cmd+N / Ctrl+N.
 * This template is written to the editor; persistence happens via auto-save
 * (debounce 500ms → save_note IPC).
 */
export const NEW_NOTE_TEMPLATE = `---\ntags: []\n---\n\n`;

/**
 * Filename validation regex matching Rust-side validation.
 * Pattern: YYYY-MM-DDTHHMMSS.md with optional _N collision suffix.
 * Used for client-side pre-validation (authoritative validation is on Rust side).
 */
export const FILENAME_PATTERN = /^\d{4}-\d{2}-\d{2}T\d{6}(_\d+)?\.md$/;
